import React, { useState, useEffect } from 'react';
import { GraduationCap, Users, Search, RefreshCw, CheckCircle, XCircle, Mail, Settings, Clock, Shield } from 'lucide-react';
import { supabase } from '../lib/supabaseClient';
import { Student } from '../types';
import emailjs from '@emailjs/browser';

const UserManagement: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'approval' | 'new_alumni' | 'old_alumni'>('approval');
  const [students, setStudents] = useState<Student[]>([]);
  const [loadingUsers, setLoadingUsers] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Approval State
  const [selectedUsers, setSelectedUsers] = useState<Set<string>>(new Set());
  const [isProcessing, setIsProcessing] = useState(false);

  // Config State
  const [showConfig, setShowConfig] = useState(false);
  const [autoApprovalDate, setAutoApprovalDate] = useState('');
  const [savingConfig, setSavingConfig] = useState(false);

  // EmailJS Configuration
  const EMAILJS_PUBLIC_KEY = 'haEhYz7iGgrGEu0kP';
  const EMAILJS_SERVICE_ID = 'service_om6q4kc';
  const EMAILJS_TEMPLATE_ID = 'template_8gw6alr';

  useEffect(() => {
    emailjs.init(EMAILJS_PUBLIC_KEY);
    // Load config from local storage (simulating persistence)
    const savedDate = localStorage.getItem('lu_auto_approval_date');
    if (savedDate) setAutoApprovalDate(savedDate);
  }, []);

  const fetchUsers = async () => {
    setLoadingUsers(true);
    let query;

    if (activeTab === 'approval') {
        // Fetch students who are NOT yet graduates (Enrolled, Graduating, etc.)
        query = supabase
            .from('students')
            .select('*')
            .neq('enrollment_status', 'Graduate')
            .order('last_name', { ascending: true });
    } else if (activeTab === 'new_alumni') {
        // Fetch students who ARE graduates
        query = supabase
            .from('students')
            .select('*')
            .eq('enrollment_status', 'Graduate')
            .order('last_name', { ascending: true });
    } else {
        // Fetch old alumni table
        query = supabase
            .from('alumni')
            .select('*')
            .order('last_name', { ascending: true });
    }

    const { data, error } = await query;

    if (!error && data) {
      setStudents(data as Student[]);
      setSelectedUsers(new Set()); // Clear selection on tab change
    }
    setLoadingUsers(false);
  };

  useEffect(() => {
    fetchUsers();
  }, [activeTab]);

  const toggleUserSelection = (id: string) => {
      const newSelection = new Set(selectedUsers);
      if (newSelection.has(id)) {
          newSelection.delete(id);
      } else {
          newSelection.add(id);
      }
      setSelectedUsers(newSelection);
  };

  const toggleSelectAll = () => {
      if (selectedUsers.size === students.length) {
          setSelectedUsers(new Set());
      } else {
          const allIds = new Set(students.map(s => s.id!));
          setSelectedUsers(allIds);
      }
  };

  const sendApprovalEmail = async (student: Student, approvedYear: string) => {
      try {
          const templateParams = {
              to_name: student.first_name,
              to_email: student.email,
              message: `Congratulations! Your alumni account has been approved. You are now officially recognized as a graduate of Batch ${approvedYear}. You may now log in to the Alumni Tracer System to update your employment profile.`,
              reply_to: 'admin@lagunauniversity.edu.ph'
          };

          await emailjs.send(EMAILJS_SERVICE_ID, EMAILJS_TEMPLATE_ID, templateParams);
          console.log(`Email sent to ${student.email}`);
          return true;
      } catch (error) {
          console.error(`Failed to send email to ${student.email}`, error);
          return false;
      }
  };

  const approveSelectedUsers = async () => {
      if (selectedUsers.size === 0) return;
      if (!confirm(`Are you sure you want to approve ${selectedUsers.size} users? This will update their status to 'Graduate' and enable their login access.`)) return;

      setIsProcessing(true);
