                <div className="flex gap-2 w-full sm:w-auto">
                    {activeTab === 'approval' && selectedUsers.size > 0 && (
                        <button 
                            onClick={handleApproveClick}
                            disabled={isProcessing}
                            className="flex-1 sm:flex-initial px-5 py-2.5 bg-rose-600 hover:bg-rose-700 text-white rounded-xl text-sm font-bold shadow-lg shadow-rose-200 transition-all flex items-center justify-center gap-2"
                        >
                            <CheckCircle size={16} />
