                                                value={formData.last_name || ''} 
                                                onChange={(e) => handleInputChange('last_name', e.target.value)}
                                                className="w-full bg-white border border-gray-200 rounded p-2 text-xs font-bold"
                                            />
                                        </div>
                                    </div>
                                    <div>
                                        <label className="text-[10px] text-luGreen font-bold block mb-1">Birthdate (Password)</label>
                                        <input 
                                            type="text" 
                                            value={formData.birthdate || ''} 
                                            onChange={(e) => handleInputChange('birthdate', e.target.value)}
                                            className={`w-full bg-white border rounded p-2 text-xs font-bold ${
                                                formData.birthdate && !isValidDateFormat(formData.birthdate) 
                                                ? 'border-red-500 text-red-600 bg-red-50' 
                                                : 'border-gray-200'
                                            }`}
                                            placeholder="MM-DD-YYYY"
                                        />
                                        {formData.birthdate && !isValidDateFormat(formData.birthdate) && (
                                            <p className="text-[10px] text-red-500 mt-1 font-bold">Must be MM-DD-YYYY</p>
                                        )}
                                    </div>
                                    <div>
                                        <label className="text-[10px] text-luGreen font-bold block mb-1">Email</label>
                                        <input 
                                            type="text" 
                                            value={formData.email || ''} 
                                            onChange={(e) => handleInputChange('email', e.target.value)}
                                            className="w-full bg-white border border-gray-200 rounded p-2 text-xs font-bold"
                                        />
                                    </div>
                                </div>
                            </div>
                            <div className="space-y-3 pt-2">
                                <button onClick={handleDataConfirmation} className="w-full py-3 bg-luGreen text-white rounded-xl text-xs font-bold shadow-md hover:bg-luGreen-dark transition-all transform active:scale-[0.98]">
                                    Next: Verify ID
                                </button>
                                <button 
                                    onClick={() => setSignupStep('upload-proof')}
                                    className="w-full py-2 text-xs font-bold text-gray-400 hover:text-luGreen transition-colors flex items-center justify-center gap-2"
                                >
                                    <ArrowLeft size={14} /> Re-upload Document
                                </button>
                            </div>
                        </div>
                    )}

                    {/* Step 4: Upload ID */}
                    {signupStep === 'upload-id' && (
                        <div className="animate-fade-in">
                            <div className="p-4 bg-amber-50 rounded-xl border border-amber-100 mb-4 text-xs text-amber-800">
                                <p className="font-bold mb-1">Identity Verification Required</p>
                                Please upload or take a photo of a valid Government or School ID to confirm that you are <strong>{formData.first_name} {formData.last_name}</strong>.
                                <br/><span className="mt-1 block text-[10px] opacity-80">Account will be created automatically upon successful verification.</span>
                            </div>
                            <div className="bg-white rounded-2xl p-1.5 shadow-sm border border-gray-100">
                                <FileUpload 
                                    onFileSelect={handleIdProcess} 
                                    isLoading={loading} 
                                    label="Upload Valid ID"
                                    acceptCamera={true}
                                />
                            </div>

                             <div className="text-center mt-6">
                                <button 
                                    onClick={() => setSignupStep('review-data')}
                                    className="text-xs font-bold text-gray-400 hover:text-luGreen transition-colors flex items-center justify-center gap-2 mx-auto"
                                >
                                    <ArrowLeft size={14} /> Back to Data Review
                                </button>
                            </div>
                        </div>
                    )}

                    <div className="mt-8 text-center md:hidden pb-4">
                        <button onClick={toggleAuth} className="text-luGreen font-bold hover:underline mt-1 text-sm">
                            Log In
                        </button>
                    </div>
                </div>

            </div>
          </div>
        </div>

      {/* Footer */}
      <footer className="w-full relative z-10 py-6 border-t border-white/40 bg-white/30 backdrop-blur-md text-gray-500 text-center text-sm mt-auto">
         <div className="container mx-auto px-4">
            <p className="font-medium text-gray-600">&copy; {new Date().getFullYear()} Laguna University</p>
         </div>
      </footer>
    </div>
  );
};

export default AuthPage;
